package com.bank.enterprise.service.impl;

import com.bank.enterprise.model.*;
import com.bank.enterprise.service.BankingServiceException;
import com.bank.enterprise.service.BankingTransactionService;
import com.bank.enterprise.security.SecurityAuditLogger;
import com.bank.enterprise.validation.TransactionValidator;

import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.annotation.Resource;
import java.math.BigDecimal;
import java.time.Instant;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingTransactionServiceImpl",
    portName = "BankingTransactionPort",
    endpointInterface = "com.bank.enterprise.service.BankingTransactionService",
    targetNamespace = "http://enterprise.bank.com/banking/v1",
    wsdlLocation = "WEB-INF/wsdl/BankingService.wsdl"
)
public class BankingTransactionServiceImpl implements BankingTransactionService {

    private static final Logger LOG = Logger.getLogger(BankingTransactionServiceImpl.class.getName());

    @Resource
    private WebServiceContext wsContext;

    private final Map<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();
    private final Map<String, TransactionResponse> transactionStore = new ConcurrentHashMap<>();
    private final TransactionValidator validator = new TransactionValidator();
    private final SecurityAuditLogger auditLogger = new SecurityAuditLogger();

    public BankingTransactionServiceImpl() {
        accountBalances.put("ACC-001", new BigDecimal("50000.00"));
        accountBalances.put("ACC-002", new BigDecimal("30000.00"));
        accountBalances.put("ACC-003", new BigDecimal("75000.00"));
        accountBalances.put("ACC-004", new BigDecimal("10000.00"));
    }

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) throws BankingServiceException {
        LOG.info("Processing transaction: " + request.getTransactionId());
        auditLogger.logTransactionAttempt(request);

        validator.validateTransactionRequest(request);

        String fromAccount = request.getFromAccount();
        String toAccount = request.getToAccount();
        BigDecimal amount = request.getAmount();

        TransactionResponse response = new TransactionResponse();
        response.setTransactionId(request.getTransactionId());
        response.setProcessedTimestamp(Instant.now().toString());

        try {
            switch (request.getTransactionType()) {
                case TRANSFER:
                    processTransfer(fromAccount, toAccount, amount);
                    break;
                case DEPOSIT:
                    processDeposit(toAccount, amount);
                    break;
                case WITHDRAWAL:
                    processWithdrawal(fromAccount, amount);
                    break;
                case PAYMENT:
                    processPayment(fromAccount, toAccount, amount);
                    break;
                case REFUND:
                    processRefund(toAccount, amount);
                    break;
                default:
                    throw new BankingServiceException("Unsupported transaction type", "ERR_UNSUPPORTED_TYPE");
            }

            response.setStatus(TransactionStatus.SUCCESS);
            response.setMessage("Transaction processed successfully");
            response.setConfirmationNumber("CNF-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase());

        } catch (BankingServiceException e) {
            response.setStatus(TransactionStatus.FAILED);
            response.setMessage(e.getMessage());
            response.setErrorCode(e.getErrorCode());
            auditLogger.logTransactionFailure(request, e);
        }

        transactionStore.put(request.getTransactionId(), response);
        auditLogger.logTransactionResult(request, response);
        return response;
    }

    @Override
    public AccountBalanceResponse getAccountBalance(AccountBalanceRequest request) throws BankingServiceException {
        LOG.info("Fetching balance for account: " + request.getAccountNumber());

        if (request.getAccountNumber() == null || request.getAccountNumber().isEmpty()) {
            throw new BankingServiceException("Account number is required", "ERR_MISSING_ACCOUNT");
        }

        BigDecimal balance = accountBalances.get(request.getAccountNumber());
        if (balance == null) {
            throw new BankingServiceException("Account not found: " + request.getAccountNumber(), "ERR_ACCOUNT_NOT_FOUND");
        }

        AccountBalanceResponse response = new AccountBalanceResponse();
        response.setAccountNumber(request.getAccountNumber());
        response.setAvailableBalance(balance);
        response.setCurrentBalance(balance);
        response.setCurrency(request.getCurrency() != null ? request.getCurrency() : "USD");
        response.setLastUpdated(Instant.now().toString());

        return response;
    }

    @Override
    public TransactionResponse getTransactionStatus(String transactionId) throws BankingServiceException {
        LOG.info("Getting status for transaction: " + transactionId);

        if (transactionId == null || transactionId.isEmpty()) {
            throw new BankingServiceException("Transaction ID is required", "ERR_MISSING_TXN_ID");
        }

        TransactionResponse response = transactionStore.get(transactionId);
        if (response == null) {
            throw new BankingServiceException("Transaction not found: " + transactionId, "ERR_TXN_NOT_FOUND");
        }

        return response;
    }

    @Override
    public TransactionResponse reverseTransaction(String transactionId, String reason) throws BankingServiceException {
        LOG.info("Reversing transaction: " + transactionId + " Reason: " + reason);

        TransactionResponse originalTxn = transactionStore.get(transactionId);
        if (originalTxn == null) {
            throw new BankingServiceException("Original transaction not found", "ERR_TXN_NOT_FOUND");
        }

        if (originalTxn.getStatus() != TransactionStatus.SUCCESS) {
            throw new BankingServiceException("Cannot reverse non-successful transaction", "ERR_INVALID_REVERSAL");
        }

        TransactionResponse reversalResponse = new TransactionResponse();
        reversalResponse.setTransactionId("REV-" + transactionId);
        reversalResponse.setStatus(TransactionStatus.SUCCESS);
        reversalResponse.setMessage("Transaction reversed successfully. Reason: " + reason);
        reversalResponse.setConfirmationNumber("REV-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase());
        reversalResponse.setProcessedTimestamp(Instant.now().toString());

        transactionStore.put(reversalResponse.getTransactionId(), reversalResponse);
        return reversalResponse;
    }

    private synchronized void processTransfer(String from, String to, BigDecimal amount) throws BankingServiceException {
        BigDecimal fromBalance = accountBalances.get(from);
        BigDecimal toBalance = accountBalances.get(to);

        if (fromBalance == null) throw new BankingServiceException("Source account not found", "ERR_SRC_NOT_FOUND");
        if (toBalance == null) throw new BankingServiceException("Destination account not found", "ERR_DST_NOT_FOUND");
        if (fromBalance.compareTo(amount) < 0) throw new BankingServiceException("Insufficient funds", "ERR_INSUFFICIENT_FUNDS");

        accountBalances.put(from, fromBalance.subtract(amount));
        accountBalances.put(to, toBalance.add(amount));
    }

    private synchronized void processDeposit(String account, BigDecimal amount) throws BankingServiceException {
        BigDecimal balance = accountBalances.get(account);
        if (balance == null) throw new BankingServiceException("Account not found", "ERR_ACCOUNT_NOT_FOUND");
        accountBalances.put(account, balance.add(amount));
    }

    private synchronized void processWithdrawal(String account, BigDecimal amount) throws BankingServiceException {
        BigDecimal balance = accountBalances.get(account);
        if (balance == null) throw new BankingServiceException("Account not found", "ERR_ACCOUNT_NOT_FOUND");
        if (balance.compareTo(amount) < 0) throw new BankingServiceException("Insufficient funds", "ERR_INSUFFICIENT_FUNDS");
        accountBalances.put(account, balance.subtract(amount));
    }

    private synchronized void processPayment(String from, String to, BigDecimal amount) throws BankingServiceException {
        processTransfer(from, to, amount);
    }

    private synchronized void processRefund(String account, BigDecimal amount) throws BankingServiceException {
        processDeposit(account, amount);
    }
}

