package com.bank.enterprise.validation;

import com.bank.enterprise.model.TransactionRequest;
import com.bank.enterprise.service.BankingServiceException;

import java.math.BigDecimal;

public class TransactionValidator {

    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");

    public void validateTransactionRequest(TransactionRequest request) throws BankingServiceException {
        if (request == null) {
            throw new BankingServiceException("Transaction request cannot be null", "ERR_NULL_REQUEST");
        }
        if (request.getTransactionId() == null || request.getTransactionId().trim().isEmpty()) {
            throw new BankingServiceException("Transaction ID is required", "ERR_MISSING_TXN_ID");
        }
        if (request.getAmount() == null) {
            throw new BankingServiceException("Amount is required", "ERR_MISSING_AMOUNT");
        }
        if (request.getAmount().compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
            throw new BankingServiceException("Amount must be at least " + MIN_TRANSACTION_AMOUNT, "ERR_AMOUNT_TOO_LOW");
        }
        if (request.getAmount().compareTo(MAX_TRANSACTION_AMOUNT) > 0) {
            throw new BankingServiceException("Amount exceeds maximum limit of " + MAX_TRANSACTION_AMOUNT, "ERR_AMOUNT_TOO_HIGH");
        }
        if (request.getTransactionType() == null) {
            throw new BankingServiceException("Transaction type is required", "ERR_MISSING_TYPE");
        }
        if (request.getCurrency() == null || request.getCurrency().trim().isEmpty()) {
            throw new BankingServiceException("Currency is required", "ERR_MISSING_CURRENCY");
        }

        switch (request.getTransactionType()) {
            case TRANSFER:
            case PAYMENT:
                if (request.getFromAccount() == null || request.getFromAccount().trim().isEmpty()) {
                    throw new BankingServiceException("Source account required for transfers", "ERR_MISSING_SRC");
                }
                if (request.getToAccount() == null || request.getToAccount().trim().isEmpty()) {
                    throw new BankingServiceException("Destination account required for transfers", "ERR_MISSING_DST");
                }
                if (request.getFromAccount().equals(request.getToAccount())) {
                    throw new BankingServiceException("Source and destination accounts must differ", "ERR_SAME_ACCOUNT");
                }
                break;
            case DEPOSIT:
            case REFUND:
                if (request.getToAccount() == null || request.getToAccount().trim().isEmpty()) {
                    throw new BankingServiceException("Destination account required for deposits", "ERR_MISSING_DST");
                }
                break;
            case WITHDRAWAL:
                if (request.getFromAccount() == null || request.getFromAccount().trim().isEmpty()) {
                    throw new BankingServiceException("Source account required for withdrawals", "ERR_MISSING_SRC");
                }
                break;
        }
    }
}

