package com.bank.enterprise.security;

import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;
import org.apache.wss4j.dom.WSConstants;

import java.util.HashMap;
import java.util.Map;

public class WsSecurityConfig {

    public static WSS4JInInterceptor createInInterceptor() {
        Map<String, Object> inProps = new HashMap<>();

        // Actions: Timestamp validation, UsernameToken, Signature verification, Encryption
        inProps.put(WSHandlerConstants.ACTION,
            WSHandlerConstants.TIMESTAMP + " " +
            WSHandlerConstants.USERNAME_TOKEN + " " +
            WSHandlerConstants.SIGNATURE + " " +
            WSHandlerConstants.ENCRYPT);

        // Password callback for UsernameToken validation
        inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS,
            ServerPasswordCallback.class.getName());

        // Signature verification properties
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");

        // Decryption properties
        inProps.put(WSHandlerConstants.DEC_PROP_FILE, "server-crypto.properties");

        // Signature algorithm
        inProps.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        inProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");

        // Timestamp TTL (5 minutes)
        inProps.put(WSHandlerConstants.TTL_TIMESTAMP, "300");
        inProps.put(WSHandlerConstants.TIMESTAMP_STRICT, "true");

        // Require signed elements
        inProps.put(WSHandlerConstants.IS_BSP_COMPLIANT, "true");

        return new WSS4JInInterceptor(inProps);
    }

    public static WSS4JOutInterceptor createOutInterceptor() {
        Map<String, Object> outProps = new HashMap<>();

        // Actions: Add timestamp, sign, encrypt
        outProps.put(WSHandlerConstants.ACTION,
            WSHandlerConstants.TIMESTAMP + " " +
            WSHandlerConstants.SIGNATURE + " " +
            WSHandlerConstants.ENCRYPT);

        // Signing properties
        outProps.put(WSHandlerConstants.USER, "bankServiceUser");
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");

        // Parts to sign: Body, Timestamp, and addressing headers
        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
            "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body;" +
            "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp");

        // Encryption properties
        outProps.put(WSHandlerConstants.ENCRYPTION_USER, "clientApp1");
        outProps.put(WSHandlerConstants.ENC_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.ENC_KEY_TRANSPORT, "http://www.w3.org/2001/04/xmlenc#rsa-oaep-mgf1p");
        outProps.put(WSHandlerConstants.ENC_SYM_ALGO, "http://www.w3.org/2001/04/xmlenc#aes256-cbc");

        // Password callback
        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS,
            ServerPasswordCallback.class.getName());

        // Signature algorithm
        outProps.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        outProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");

        return new WSS4JOutInterceptor(outProps);
    }

    public static WSS4JInInterceptor createClientInInterceptor() {
        Map<String, Object> inProps = new HashMap<>();

        inProps.put(WSHandlerConstants.ACTION,
            WSHandlerConstants.TIMESTAMP + " " +
            WSHandlerConstants.SIGNATURE + " " +
            WSHandlerConstants.ENCRYPT);

        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "client-crypto.properties");
        inProps.put(WSHandlerConstants.DEC_PROP_FILE, "client-crypto.properties");
        inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, ClientPasswordCallback.class.getName());

        return new WSS4JInInterceptor(inProps);
    }

    public static WSS4JOutInterceptor createClientOutInterceptor() {
        Map<String, Object> outProps = new HashMap<>();

        outProps.put(WSHandlerConstants.ACTION,
            WSHandlerConstants.TIMESTAMP + " " +
            WSHandlerConstants.USERNAME_TOKEN + " " +
            WSHandlerConstants.SIGNATURE + " " +
            WSHandlerConstants.ENCRYPT);

        outProps.put(WSHandlerConstants.USER, "clientApp1");
        outProps.put(WSHandlerConstants.PASSWORD_TYPE, WSConstants.PW_DIGEST);

        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "client-crypto.properties");
        outProps.put(WSHandlerConstants.SIG_KEY_ID, "DirectReference");

        outProps.put(WSHandlerConstants.SIGNATURE_PARTS,
            "{Element}{http://schemas.xmlsoap.org/soap/envelope/}Body;" +
            "{Element}{http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd}Timestamp");

        outProps.put(WSHandlerConstants.ENCRYPTION_USER, "bankServiceUser");
        outProps.put(WSHandlerConstants.ENC_PROP_FILE, "client-crypto.properties");
        outProps.put(WSHandlerConstants.ENC_KEY_TRANSPORT, "http://www.w3.org/2001/04/xmlenc#rsa-oaep-mgf1p");
        outProps.put(WSHandlerConstants.ENC_SYM_ALGO, "http://www.w3.org/2001/04/xmlenc#aes256-cbc");

        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, ClientPasswordCallback.class.getName());

        outProps.put(WSHandlerConstants.SIG_ALGO, "http://www.w3.org/2001/04/xmldsig-more#rsa-sha256");
        outProps.put(WSHandlerConstants.SIG_DIGEST_ALGO, "http://www.w3.org/2001/04/xmlenc#sha256");

        return new WSS4JOutInterceptor(outProps);
    }
}

// =======================================
// 8. SOAP Message Parser and Signature Extractor
// =======================================
package com.bank.enterprise.security;

import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.KeyValue;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.StringReader;
import java.io.StringWriter;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.X509Certificate;
import java.util.*;
import java.util.logging.Logger;

public class SoapMessageParser {

    private static final Logger LOG = Logger.getLogger(SoapMessageParser.class.getName());

    private static final String SOAP_ENV_NS = "http://schemas.xmlsoap.org/soap/envelope/";
    private static final String SOAP12_ENV_NS = "http://www.w3.org/2003/05/soap-envelope";
    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String DS_NS = "http://www.w3.org/2000/09/xmldsig#";

    public Document parseSoapMessage(String soapXml) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);

        // Security: prevent XXE attacks
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setExpandEntityReferences(false);

        DocumentBuilder db = dbf.newDocumentBuilder();
        return db.parse(new InputSource(new StringReader(soapXml)));
    }

    public Element extractSoapBody(Document doc) {
        // Try SOAP 1.1
        NodeList bodyList = doc.getElementsByTagNameNS(SOAP_ENV_NS, "Body");
        if (bodyList.getLength() == 0) {
            // Try SOAP 1.2
            bodyList = doc.getElementsByTagNameNS(SOAP12_ENV_NS, "Body");
        }
        if (bodyList.getLength() > 0) {
            return (Element) bodyList.item(0);
        }
        return null;
    }

    public Element extractSecurityHeader(Document doc) {
        NodeList securityList = doc.getElementsByTagNameNS(WSSE_NS, "Security");
        if (securityList.getLength() > 0) {
            return (Element) securityList.item(0);
        }
        return null;
    }

    public List<SignedElementInfo> extractSignedElements(Document doc) throws Exception {
        List<SignedElementInfo> signedElements = new ArrayList<>();

        Element securityHeader = extractSecurityHeader(doc);
        if (securityHeader == null) {
            LOG.warning("No WS-Security header found in SOAP message");
            return signedElements;
        }

        NodeList signatureNodes = securityHeader.getElementsByTagNameNS(DS_NS, "Signature");

        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElement = (Element) signatureNodes.item(i);

            // Extract SignedInfo
            NodeList signedInfoNodes = signatureElement.getElementsByTagNameNS(DS_NS, "SignedInfo");
            if (signedInfoNodes.getLength() == 0) continue;

            Element signedInfo = (Element) signedInfoNodes.item(0);

            // Extract all Reference elements
            NodeList referenceNodes = signedInfo.getElementsByTagNameNS(DS_NS, "Reference");

            for (int j = 0; j < referenceNodes.getLength(); j++) {
                Element reference = (Element) referenceNodes.item(j);
                String uri = reference.getAttribute("URI");

                SignedElementInfo info = new SignedElementInfo();
                info.setReferenceUri(uri);

                // Extract DigestMethod
                NodeList digestMethodNodes = reference.getElementsByTagNameNS(DS_NS, "DigestMethod");
                if (digestMethodNodes.getLength() > 0) {
                    info.setDigestAlgorithm(((Element) digestMethodNodes.item(0)).getAttribute("Algorithm"));
                }

                // Extract DigestValue
                NodeList digestValueNodes = reference.getElementsByTagNameNS(DS_NS, "DigestValue");
                if (digestValueNodes.getLength() > 0) {
                    info.setDigestValue(digestValueNodes.item(0).getTextContent());
                }

                // Extract Transforms
                NodeList transformNodes = reference.getElementsByTagNameNS(DS_NS, "Transform");
                List<String> transforms = new ArrayList<>();
                for (int k = 0; k < transformNodes.getLength(); k++) {
                    transforms.add(((Element) transformNodes.item(k)).getAttribute("Algorithm"));
                }
                info.setTransforms(transforms);

                // Resolve the signed element by URI
                if (uri != null && uri.startsWith("#")) {
                    String id = uri.substring(1);
                    Element signedElement = findElementById(doc, id);
                    if (signedElement != null) {
                        info.setElementLocalName(signedElement.getLocalName());
                        info.setElementNamespace(signedElement.getNamespaceURI());
                        info.setElementContent(elementToString(signedElement));
                    }
                }

                signedElements.add(info);
                LOG.info("Found signed element - URI: " + uri +
                    ", Element: " + info.getElementLocalName() +
                    ", Digest: " + info.getDigestAlgorithm());
            }

            // Extract SignatureMethod
            NodeList sigMethodNodes = signedInfo.getElementsByTagNameNS(DS_NS, "SignatureMethod");
            if (sigMethodNodes.getLength() > 0) {
                String sigAlgorithm = ((Element) sigMethodNodes.item(0)).getAttribute("Algorithm");
                for (SignedElementInfo sei : signedElements) {
                    sei.setSignatureAlgorithm(sigAlgorithm);
                }
            }

            // Extract CanonicalizationMethod
            NodeList canonNodes = signedInfo.getElementsByTagNameNS(DS_NS, "CanonicalizationMethod");
            if (canonNodes.getLength() > 0) {
                String canonAlgorithm = ((Element) canonNodes.item(0)).getAttribute("Algorithm");
                for (SignedElementInfo sei : signedElements) {
                    sei.setCanonicalizationAlgorithm(canonAlgorithm);
                }
            }
        }

        return signedElements;
    }

    private Element findElementById(Document doc, String id) {
        // Check wsu:Id attribute
        NodeList allElements = doc.getElementsByTagName("*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            if (id.equals(element.getAttributeNS(WSU_NS, "Id")) ||
                id.equals(element.getAttribute("Id")) ||
                id.equals(element.getAttribute("xml:id"))) {
                return element;
            }
        }
        return null;
    }

    public boolean verifyXmlSignature(Document doc) throws Exception {
        Element securityHeader = extractSecurityHeader(doc);
        if (securityHeader == null) {
            throw new SecurityException("No WS-Security header found");
        }

        NodeList signatureNodes = securityHeader.getElementsByTagNameNS(DS_NS, "Signature");
        if (signatureNodes.getLength() == 0) {
            throw new SecurityException("No XML Signature found in security header");
        }

        // Register ID attributes for all elements
        registerIdAttributes(doc);

        boolean allValid = true;
        for (int i = 0; i < signatureNodes.getLength(); i++) {
            Element signatureElement = (Element) signatureNodes.item(i);

            // Create a DOMValidateContext
            KeySelector keySelector = new X509KeySelector();
            DOMValidateContext validateContext = new DOMValidateContext(keySelector, signatureElement);

            // Register ID resolver
            validateContext.setIdAttributeNS(doc.getDocumentElement(), WSU_NS, "Id");
            registerAllIds(doc, validateContext);

            // Unmarshal the XMLSignature
            XMLSignatureFactory sigFactory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = sigFactory.unmarshalXMLSignature(validateContext);

            // Validate the signature
            boolean coreValidity = signature.validate(validateContext);

            if (!coreValidity) {
                LOG.severe("Signature validation FAILED for signature #" + i);

                // Check the signature value
                boolean sv = signature.getSignatureValue().validate(validateContext);
                LOG.info("Signature value validation: " + sv);

                // Check each reference
                @SuppressWarnings("unchecked")
                List<Reference> refs = signature.getSignedInfo().getReferences();
                for (Reference ref : refs) {
                    boolean refValid = ref.validate(validateContext);
                    LOG.info("Reference [" + ref.getURI() + "] validation: " + refValid);
                }

                allValid = false;
            } else {
                LOG.info("Signature #" + i + " validation PASSED");
            }
        }

        return allValid;
    }

    private void registerIdAttributes(Document doc) {
        NodeList allElements = doc.getElementsByTagName("*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            if (element.hasAttributeNS(WSU_NS, "Id")) {
                element.setIdAttributeNS(WSU_NS, "Id", true);
            }
            if (element.hasAttribute("Id")) {
                element.setIdAttribute("Id", true);
            }
        }
    }

    private void registerAllIds(Document doc, DOMValidateContext context) {
        NodeList allElements = doc.getElementsByTagName("*");
        for (int i = 0; i < allElements.getLength(); i++) {
            Element element = (Element) allElements.item(i);
            if (element.hasAttributeNS(WSU_NS, "Id")) {
                context.setIdAttributeNS(element, WSU_NS, "Id");
            }
        }
    }

    public Map<String, String> extractUsernameToken(Document doc) {
        Map<String, String> tokenInfo = new HashMap<>();

        Element securityHeader = extractSecurityHeader(doc);
        if (securityHeader == null) return tokenInfo;

        NodeList usernameTokenNodes = securityHeader.getElementsByTagNameNS(WSSE_NS, "UsernameToken");
        if (usernameTokenNodes.getLength() == 0) return tokenInfo;

        Element usernameToken = (Element) usernameTokenNodes.item(0);

        NodeList usernameNodes = usernameToken.getElementsByTagNameNS(WSSE_NS, "Username");
        if (usernameNodes.getLength() > 0) {
            tokenInfo.put("username", usernameNodes.item(0).getTextContent());
        }

        NodeList passwordNodes = usernameToken.getElementsByTagNameNS(WSSE_NS, "Password");
        if (passwordNodes.getLength() > 0) {
            Element passwordElement = (Element) passwordNodes.item(0);
            tokenInfo.put("password", passwordElement.getTextContent());
            tokenInfo.put("passwordType", passwordElement.getAttribute("Type"));
        }

        NodeList nonceNodes = usernameToken.getElementsByTagNameNS(WSSE_NS, "Nonce");
        if (nonceNodes.getLength() > 0) {
            tokenInfo.put("nonce", nonceNodes.item(0).getTextContent());
        }

        NodeList createdNodes = usernameToken.getElementsByTagNameNS(WSU_NS, "Created");
        if (createdNodes.getLength() > 0) {
            tokenInfo.put("created", createdNodes.item(0).getTextContent());
        }

        return tokenInfo;
    }

    public Map<String, String> extractTimestamp(Document doc) {
        Map<String, String> timestampInfo = new HashMap<>();

        Element securityHeader = extractSecurityHeader(doc);
        if (securityHeader == null) return timestampInfo;

        NodeList timestampNodes = securityHeader.getElementsByTagNameNS(WSU_NS, "Timestamp");
        if (timestampNodes.getLength() == 0) return timestampInfo;

        Element timestamp = (Element) timestampNodes.item(0);

        NodeList createdNodes = timestamp.getElementsByTagNameNS(WSU_NS, "Created");
        if (createdNodes.getLength() > 0) {
            timestampInfo.put("created", createdNodes.item(0).getTextContent());
        }

        NodeList expiresNodes = timestamp.getElementsByTagNameNS(WSU_NS, "Expires");
        if (expiresNodes.getLength() > 0) {
            timestampInfo.put("expires", expiresNodes.item(0).getTextContent());
        }

        return timestampInfo;
    }

    private String elementToString(Element element) {
        try {
            TransformerFactory tf = TransformerFactory.newInstance();
            Transformer transformer = tf.newTransformer();
            StringWriter writer = new StringWriter();
            transformer.transform(new DOMSource(element), new StreamResult(writer));
            return writer.toString();
        } catch (Exception e) {
            return "[unable to serialize element]";
        }
    }

    // Inner class for X509 key selection during signature verification
    private static class X509KeySelector extends KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, KeySelector.Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context)
                throws KeySelectorException {

            if (keyInfo == null) {
                throw new KeySelectorException("KeyInfo is null");
            }

            @SuppressWarnings("unchecked")
            List<XMLStructure> keyInfoContent = keyInfo.getContent();

            for (XMLStructure structure : keyInfoContent) {
                if (structure instanceof X509Data) {
                    X509Data x509Data = (X509Data) structure;
                    @SuppressWarnings("unchecked")
                    List<Object> x509Content = x509Data.getContent();

                    for (Object item : x509Content) {
                        if (item instanceof X509Certificate) {
                            final PublicKey publicKey = ((X509Certificate) item).getPublicKey();
                            return () -> publicKey;
                        }
                    }
                } else if (structure instanceof KeyValue) {
                    try {
                        final PublicKey publicKey = ((KeyValue) structure).getPublicKey();
                        return () -> publicKey;
                    } catch (Exception e) {
                        throw new KeySelectorException("Failed to get public key", e);
                    }
                }
            }

            throw new KeySelectorException("No suitable key found in KeyInfo");
        }
    }
}

// =======================================
// 9. Signed Element Info DTO
// =======================================
package com.bank.enterprise.security;

import java.util.List;

public class SignedElementInfo {
    private String referenceUri;
    private String digestAlgorithm;
    private String digestValue;
    private List<String> transforms;
    private String elementLocalName;
    private String elementNamespace;
    private String elementContent;
    private String signatureAlgorithm;
    private String canonicalizationAlgorithm;

    public String getReferenceUri() { return referenceUri; }
    public void setReferenceUri(String referenceUri) { this.referenceUri = referenceUri; }
    public String getDigestAlgorithm() { return digestAlgorithm; }
    public void setDigestAlgorithm(String digestAlgorithm) { this.digestAlgorithm = digestAlgorithm; }
    public String getDigestValue() { return digestValue; }
    public void setDigestValue(String digestValue) { this.digestValue = digestValue; }
    public List<String> getTransforms() { return transforms; }
    public void setTransforms(List<String> transforms) { this.transforms = transforms; }
    public String getElementLocalName() { return elementLocalName; }
    public void setElementLocalName(String elementLocalName) { this.elementLocalName = elementLocalName; }
    public String getElementNamespace() { return elementNamespace; }
    public void setElementNamespace(String elementNamespace) { this.elementNamespace = elementNamespace; }
    public String getElementContent() { return elementContent; }
    public void setElementContent(String elementContent) { this.elementContent = elementContent; }
    public String getSignatureAlgorithm() { return signatureAlgorithm; }
    public void setSignatureAlgorithm(String signatureAlgorithm) { this.signatureAlgorithm = signatureAlgorithm; }
    public String getCanonicalizationAlgorithm() { return canonicalizationAlgorithm; }
    public void setCanonicalizationAlgorithm(String canonicalizationAlgorithm) { this.canonicalizationAlgorithm = canonicalizationAlgorithm; }

    @Override
    public String toString() {
        return "SignedElementInfo{" +
                "referenceUri='" + referenceUri + '\'' +
                ", elementLocalName='" + elementLocalName + '\'' +
                ", digestAlgorithm='" + digestAlgorithm + '\'' +
                ", signatureAlgorithm='" + signatureAlgorithm + '\'' +
                '}';
    }
}

// =======================================
// 10. Security Audit Logger
// =======================================
package com.bank.enterprise.security;

import com.bank.enterprise.model.TransactionRequest;
import com.bank.enterprise.model.TransactionResponse;
import com.bank.enterprise.service.BankingServiceException;

import java.time.Instant;
import java.util.logging.Logger;

public class SecurityAuditLogger {

    private static final Logger AUDIT_LOG = Logger.getLogger("BANKING_AUDIT");

    public void logTransactionAttempt(TransactionRequest request) {
        AUDIT_LOG.info(String.format("[AUDIT][TXN_ATTEMPT] TransactionId=%s Type=%s From=%s To=%s Amount=%s Currency=%s Timestamp=%s",
            request.getTransactionId(),
            request.getTransactionType(),
            maskAccount(request.getFromAccount()),
            maskAccount(request.getToAccount()),
            request.getAmount(),
            request.getCurrency(),
            Instant.now().toString()));
    }

    public void logTransactionResult(TransactionRequest request, TransactionResponse response) {
        AUDIT_LOG.info(String.format("[AUDIT][TXN_RESULT] TransactionId=%s Status=%s Confirmation=%s Timestamp=%s",
            response.getTransactionId(),
            response.getStatus(),
            response.getConfirmationNumber(),
            Instant.now().toString()));
    }

    public void logTransactionFailure(TransactionRequest request, BankingServiceException ex) {
        AUDIT_LOG.warning(String.format("[AUDIT][TXN_FAILURE] TransactionId=%s ErrorCode=%s Message=%s Timestamp=%s",
            request.getTransactionId(),
            ex.getErrorCode(),
            ex.getMessage(),
            Instant.now().toString()));
    }

    public void logSecurityEvent(String eventType, String details) {
        AUDIT_LOG.info(String.format("[AUDIT][SECURITY] Event=%s Details=%s Timestamp=%s",
            eventType, details, Instant.now().toString()));
    }

    public void logSignatureVerification(boolean success, String details) {
        String level = success ? "INFO" : "SEVERE";
        AUDIT_LOG.info(String.format("[AUDIT][SIG_VERIFY] Success=%s Details=%s Timestamp=%s",
            success, details, Instant.now().toString()));
    }

    private String maskAccount(String accountNumber) {
        if (accountNumber == null || accountNumber.length() <= 4) return "****";
        return "****" + accountNumber.substring(accountNumber.length() - 4);
    }
}

// =======================================
// 11. Custom CXF Interceptor for SOAP Message Processing
// =======================================
package com.bank.enterprise.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.w3c.dom.Document;

import javax.xml.soap.SOAPMessage;
import java.util.List;
import java.util.Map;
import java.util.logging.Logger;

public class SecurityValidationInterceptor extends AbstractSoapInterceptor {

    private static final Logger LOG = Logger.getLogger(SecurityValidationInterceptor.class.getName());
    private final SoapMessageParser messageParser = new SoapMessageParser();
    private final SecurityAuditLogger auditLogger = new SecurityAuditLogger();

    public SecurityValidationInterceptor() {
        super(Phase.PRE_INVOKE);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        LOG.info("SecurityValidationInterceptor processing incoming message");

        try {
            SOAPMessage soapMessage = message.getContent(SOAPMessage.class);
            if (soapMessage == null) {
                LOG.warning("No SOAP message content found");
                return;
            }

            Document doc = soapMessage.getSOAPPart();

            // Extract and log security header info
            Map<String, String> usernameToken = messageParser.extractUsernameToken(doc);
            if (!usernameToken.isEmpty()) {
                auditLogger.logSecurityEvent("USERNAME_TOKEN",
                    "User: " + usernameToken.get("username") +
                    ", Type: " + usernameToken.get("passwordType"));
            }

            // Validate timestamp
            Map<String, String> timestamp = messageParser.extractTimestamp(doc);
            if (!timestamp.isEmpty()) {
                auditLogger.logSecurityEvent("TIMESTAMP_FOUND",
                    "Created: " + timestamp.get("created") +
                    ", Expires: " + timestamp.get("expires"));
            }

            // Extract and log signed elements
            List<SignedElementInfo> signedElements = messageParser.extractSignedElements(doc);
            for (SignedElementInfo signedElement : signedElements) {
                auditLogger.logSecurityEvent("SIGNED_ELEMENT",
                    "URI: " + signedElement.getReferenceUri() +
                    ", Element: " + signedElement.getElementLocalName() +
                    ", SigAlgo: " + signedElement.getSignatureAlgorithm());
            }

            // Verify that required elements are signed
            verifyRequiredSignatures(signedElements);

            LOG.info("Security validation completed successfully");

        } catch (SecurityException se) {
            auditLogger.logSecurityEvent("SECURITY_VIOLATION", se.getMessage());
            throw new Fault(new Exception("Security validation failed: " + se.getMessage()));
        } catch (Exception e) {
            LOG.severe("Error during security validation: " + e.getMessage());
            throw new Fault(new Exception("Security processing error", e));
        }
    }

    private void verifyRequiredSignatures(List<SignedElementInfo> signedElements) {
        boolean bodyIsSigned = false;
        boolean timestampIsSigned = false;

        for (SignedElementInfo info : signedElements) {
            if ("Body".equals(info.getElementLocalName())) {
                bodyIsSigned = true;
            }
            if ("Timestamp".equals(info.getElementLocalName())) {
                timestampIsSigned = true;
            }
        }

        if (!bodyIsSigned) {
            throw new SecurityException("SOAP Body must be signed");
        }
        if (!timestampIsSigned) {
            throw new SecurityException("Timestamp must be signed");
        }
    }
}

// =======================================
// 12. CXF Endpoint Publisher / Server Configuration
// =======================================
package com.bank.enterprise.server;

import com.bank.enterprise.security.SecurityValidationInterceptor;
import com.bank.enterprise.security.WsSecurityConfig;
import com.bank.enterprise.service.impl.BankingTransactionServiceImpl;
import org.apache.cxf.Bus;
import org.apache.cxf.BusFactory;
import org.apache.cxf.jaxws.JaxWsServerFactoryBean;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

public class BankingServicePublisher {

    private static final Logger LOG = Logger.getLogger(BankingServicePublisher.class.getName());
    private static final String SERVICE_URL = "https://localhost:8443/banking/v1/transactions";

    public static void main(String[] args) {
        publishWithCxf();
    }

    public static void publishWithCxf() {
        LOG.info("Starting Banking Transaction Service with Apache CXF and WS-Security...");

        Bus bus = BusFactory.getDefaultBus();

        JaxWsServerFactoryBean factory = new JaxWsServerFactoryBean();
        factory.setServiceClass(BankingTransactionServiceImpl.class);
        factory.setAddress(SERVICE_URL);
        factory.setServiceBean(new BankingTransactionServiceImpl());

        // Add WS-Security interceptors
        WSS4JInInterceptor inInterceptor = WsSecurityConfig.createInInterceptor();
        WSS4JOutInterceptor outInterceptor = WsSecurityConfig.createOutInterceptor();

        factory.getInInterceptors().add(inInterceptor);
        factory.getOutInterceptors().add(outInterceptor);

        // Add custom security validation interceptor
        factory.getInInterceptors().add(new SecurityValidationInterceptor());

        // Add logging interceptors for debugging
        factory.getInInterceptors().add(new org.apache.cxf.interceptor.LoggingInInterceptor());
        factory.getOutInterceptors().add(new org.apache.cxf.interceptor.LoggingOutInterceptor());

        factory.create();

        LOG.info("Banking Transaction Service published at: " + SERVICE_URL);
        LOG.info("WSDL available at: " + SERVICE_URL + "?wsdl");
    }

    public static void publishWithJaxWs() {
        LOG.info("Starting Banking Transaction Service with JAX-WS...");
        Endpoint endpoint = Endpoint.publish(
            "http://localhost:8080/banking/v1/transactions",
            new BankingTransactionServiceImpl()
        );
        LOG.info("Service published. Is published: " + endpoint.isPublished());
    }
}

